def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip(); v = v.strip()
            if k in ('infeed', 'contam'):
                out[k] = int(v) if v.lstrip('-').isdigit() else 0
    # A manifest can never declare more contaminant than total infeed.
    if 'infeed' in out and 'contam' in out:
        out['contam'] = min(out['contam'], out['infeed'])
    return out
